import { Resend } from 'resend';

const resend = new Resend(process.env.RESEND_API_KEY);

export async function sendWelcomeEmail(email: string, handle: string) {
  const siteUrl = process.env.NEXT_PUBLIC_SITE_URL || 'http://localhost:3000';
  const profileUrl = `${siteUrl}/@${handle}`;

  try {
    const { data, error } = await resend.emails.send({
      from: 'Bookmarks <onboarding@resend.dev>',
      to: email,
      subject: 'Welcome to Bookmarks!',
      html: `
        <div style="font-family: sans-serif; max-width: 600px; margin: 0 auto;">
          <h1 style="color: #111;">Welcome! 👋</h1>
          <p style="font-size: 16px; line-height: 1.5; color: #444;">
            We're excited to have you on Bookmarks. Your public profile is now ready!
          </p>
          <div style="margin: 32px 0;">
            <a href="${profileUrl}" 
               style="background-color: #6c47ff; color: white; padding: 12px 24px; text-decoration: none; border-radius: 8px; font-weight: 600; display: inline-block;">
              View Your Profile
            </a>
          </div>
          <hr style="border: none; border-top: 1px solid #eee; margin: 32px 0;" />
          <p style="font-size: 14px; color: #666;">
            Next step: Start adding your favorite bookmarks from your dashboard to build your collection.
          </p>
        </div>
      `,
    });

    if (error) {
      console.error('Error sending welcome email:', error);
      return { success: false, error };
    }

    return { success: true, data };
  } catch (err) {
    console.error('Unexpected error sending welcome email:', err);
    return { success: false, error: err };
  }
}

