The complete TypeScript code for `src/lib/email.ts` is provided below. This implementation uses the `resend` library to send a branded welcome email with a styled action button.

```typescript
import { Resend } from 'resend';

const resend = new Resend(process.env.RESEND_API_KEY);

/**
 * Sends a welcome email to a new user using Resend.
 * 
 * @param email - The recipient's email address.
 * @param handle - The user's unique handle for their public profile.
 */
export async function sendWelcomeEmail(email: string, handle: string) {
  const siteUrl = process.env.NEXT_PUBLIC_SITE_URL || 'http://localhost:3000';
  const profileUrl = `${siteUrl}/@${handle}`;

  try {
    const { data, error } = await resend.emails.send({
      from: 'Bookmarks <onboarding@resend.dev>',
      to: email,
      subject: 'Welcome to Bookmarks!',
      html: `
        <div style="font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Helvetica, Arial, sans-serif; max-width: 600px; margin: 0 auto; padding: 20px;">
          <h1 style="color: #111; font-size: 24px; font-weight: 700; margin-bottom: 24px;">Welcome! 👋</h1>

          <p style="font-size: 16px; line-height: 1.6; color: #444; margin-bottom: 32px;">
            We're excited to have you on Bookmarks! Your public profile is now live and ready for your collection.
          </p>

          <div style="margin-bottom: 32px;">
            <a href="${profileUrl}" 
               style="background-color: #6c47ff; color: #ffffff; padding: 12px 24px; text-decoration: none; border-radius: 8px; font-weight: 600; display: inline-block; font-size: 16px;">
              View Your Profile
            </a>
          </div>

          <hr style="border: none; border-top: 1px solid #eaeaea; margin: 32px 0;" />

          <p style="font-size: 14px; color: #666; line-height: 1.5;">
            <strong>Next step:</strong> Start adding your favorite bookmarks from your dashboard to build your collection and share it with the world.
          </p>
        </div>
      `,
    });

    if (error) {
      console.error('Error sending welcome email:', error);
      return { success: false, error };
    }

    return { success: true, data };
  } catch (err) {
    console.error('Unexpected error sending welcome email:', err);
    return { success: false, error: err };
  }
}
```

### Key Features:
- **Resend Integration**: Initialized with `RESEND_API_KEY`.
- **Dynamic Profile URL**: Uses `NEXT_PUBLIC_SITE_URL` (falling back to localhost for development) to construct the `@handle` link.
- **Branded Styling**: Includes the requested `#6c47ff` background, white text, and 8px border radius for the button.
- **Error Handling**: Returns a standard `{ success, data/error }` object for easy consumption in your auth actions.
